        # Look for design status
        if 'Design' in text:
            lines = text.split('\n')
            for line in lines:
                line = line.strip()
                if line and len(line) > 10:
                    # Skip meta lines
                    if any(x in line for x in ['Page', 'Schedule:', 'Updates:']):
                        continue
                    if line.startswith('202') or line.startswith('Item'):
                        continue
                    # Extract project name
                    clean_name = line.replace('•', '').replace('○', '').strip()
